// =============================================
// === TERMINAL + RANDOM TICKET GENERATOR ===
// =============================================

import groovy.json.*

// ======================
// 1. HELPER FUNCTIONS
// ======================

def getNumbers() {
    return (1..48).toList()
}

def pickOne(list) {
    if (!list || list.isEmpty()) return null
    return list[new Random().nextInt(list.size())]
}

def pickSome(list, count) {
    if (!list || list.isEmpty()) return []
    def shuffled = list.toList()
    Collections.shuffle(shuffled)
    return shuffled[0..<count]
}

// ======================
// 2. GENERATE BET (Simplified - No Map)
// ======================

def generateBet(betType) {
    switch(betType) {
        case "BallNumbers":
            return pickSome(getNumbers(), 6).join(",")

        case "FirstBallUnderOver":
        case "LastBallUnderOver":
        case "FirstBallEvenOdd":
        case "LastBallEvenOdd":
        case "SumOfFirstFiveUnderOver":
            return pickOne(["under", "over"])

        case "FirstBallColor":
        case "LastBallColor":
            def colors = ["red","blue","green","yellow","brown","orange","black","purple"]
            return pickSome(colors, 4).join(",")

        case "FirstDrawnNumber":
        case "LastDrawnNumber":
        case "FirstOrLastDrawnNumber":
            return pickOne(getNumbers()).toString()

        default:
            log.warn("Unknown bet type: ${betType}")
            return null
    }
}

// ======================
// 3. SELECT TERMINAL ID
// ======================

def getTerminalList() {
    def terminalListProp = testRunner.testCase.testSuite.project
        .testSuites['GSBet _settlement']
        .testCases['TerminalCreation']
        .testSteps['Properties']
        .getPropertyValue('AllTerminalIDs')

    if (!terminalListProp) {
        log.error("AllTerminalIDs property not found!")
        assert false, "Missing AllTerminalIDs"
    }

    def cleanList = terminalListProp
        .replace("[", "")
        .replace("]", "")
        .trim()

    return cleanList.split(",").collect { it.trim() }.findAll { it }
}

def propertiesStep = testRunner.testCase.testSteps['Properties']
def terminals = getTerminalList()

def currentIndex = (propertiesStep.getPropertyValue("i") ?: "0") as Integer
if (currentIndex >= terminals.size() || currentIndex < 0) {
    currentIndex = 0
}

def selectedTerminal = terminals[currentIndex]

// Set Terminal
testRunner.testCase.setPropertyValue("CurrentWalletId", selectedTerminal)
propertiesStep.setPropertyValue("CurrentWalletId", selectedTerminal)

// Increment index
def nextIndex = (currentIndex + 1) % terminals.size()
propertiesStep.setPropertyValue("i", nextIndex.toString())

log.info("=== Terminal Selected ===")
log.info("Index: ${currentIndex} | Terminal: ${selectedTerminal} | Next: ${nextIndex}")

// ======================
// 4. GENERATE TICKET DATA
// ======================

def mainBetType = "BallNumbers"

def randomBallNumbers = generateBet(mainBetType)
def randomAmount = 10 + new Random().nextInt(91)

testRunner.testCase.setPropertyValue("RandomBallNumbers", randomBallNumbers ?: "")
testRunner.testCase.setPropertyValue("RandomAmount", randomAmount.toString())
testRunner.testCase.setPropertyValue("PayinMode", "normal")

log.info("=== Random Ticket Generated ===")
log.info("Bet Type     : ${mainBetType}")
log.info("Ball Numbers : ${randomBallNumbers}")
log.info("Amount       : ${randomAmount}")
log.info("Terminal ID  : ${selectedTerminal}")

