import groovy.json.*

def ready = false
def payinMode = context.expand('${PayinMode#Result}')

while(ready == false) {
	Thread.sleep(500)
	log.info 'Checking ticket'

	if(payinMode == "Standard") {
		def tc = testRunner.testCase.testSteps["GetByActionId"]
		tc.run(testRunner,context)
		def resp = new JsonSlurper().parseText(testRunner.testCase.getTestStepByName("GetByActionId").testRequest.response.responseContent)
		log.info resp.ResponseAction
		ready = resp.ResponseAction != 'RepeatRequest'

		/*if(resp.ResponseAction == 'DeleteRequest') {
			return false
		}*/

		if(resp.ResponseAction == 'DeleteRequest') {
			return JsonOutput.toJson(
				Status:     false,
				Message:  'Delete Request'
			)
		}

		if(resp.ResponseAction == 'StartPrinting' && resp.Ticket.Status != 'BillingPending') {
			log.info resp.ResponseAction + ' but ticket status is ' + resp.Ticket.Status
			return JsonOutput.toJson(
				Status:     false,
				Message:  'Wrong status'
			)
		}
	} else {
		def tc = testRunner.testCase.testSteps["GetByLinkedId"]
		tc.run(testRunner,context)
		def resp = new JsonSlurper().parseText(testRunner.testCase.getTestStepByName("GetByLinkedId").testRequest.response.responseContent)
		ready = resp.ResponseAction != 'RepeatRequest'

		if(resp.ResponseAction == 'DeleteRequest') {
			log.info resp.ResponseAction + ' but ticket status is ' + resp.Ticket.Status
			return JsonOutput.toJson(
				Status:     false,
				Message:  'Delete Request'
			)
		}

		if(resp.ResponseAction == 'StartPrinting' && resp.Ticket.Status != 'BillingPending') {
			log.info resp.ResponseAction + ' but ticket status is ' + resp.Ticket.Status
				//return false
				return JsonOutput.toJson(
				Status:     false,
				Message:  'Wrong status'
			)
		}

		if(resp.Ticket.Status == 'BillingPending') {
			log.info ' BP :' + resp.Ticket.Status
		}
	}
}

//return true
return JsonOutput.toJson(
	Status:     true,
	Message:  'OK'
)

import groovy.time.TimeCategory

use (TimeCategory) {
	TimeZone.setDefault(TimeZone.getTimeZone('UTC'))
	def now = new Date()
	return now.format("yyyy-MM-dd'T'HH:mm:MM.SSS'Z'")
}

// Get current index
def iProp = testRunner.testCase.testSteps['Properties']
def i = (iProp.getPropertyValue("i") ?: "0") as Integer

// Get the result string from the other test case
def tokens = testRunner.testCase.testSuite.project
                .testSuites['GSBet _settlement']
                .testCases['TerminalCreation']
                .testSteps['Properties']
                .getPropertyValue('AllTerminalIDs')

if (!tokens) {
    log.error "Result property is empty or null!"
    testRunner.testCase.testSteps['Properties'].setPropertyValue("i", "0")
    return
}

def walletIds1 = tokens.toString().trim()

// Remove surrounding brackets if present
def walletsIds2 = walletIds1
if (walletsIds2.startsWith('[') && walletsIds2.endsWith(']')) {
    walletsIds2 = walletsIds2.substring(1, walletsIds2.length() - 1)
}

def list = walletsIds2.tokenize(', ')

// Remove any extra whitespace from each item
list = list*.trim().findAll { it }

// Log info
log.info "Wallet list size: ${list.size()} | Current i: ${i}"

// Main loop logic
if (i < list.size()) {
    // Still have items to process
    def currentWalletId = list[i]
    log.info "Processing wallet ID [${i}]: ${currentWalletId}"

    // Optional: set the current wallet ID to a property for next steps
    testRunner.testCase.testSteps['Properties'].setPropertyValue("CurrentWalletId", currentWalletId)

    i++
    iProp.setPropertyValue("i", i as String)

    testRunner.gotoStepByName("AddTerminalLoginPin")
} 
else {
    // End of list - reset
    log.info "End of wallet list reached. Resetting counter."
    iProp.setPropertyValue("i", "0")
}
